-- Import the one strict Nutro row present in the current reviewed feed but
-- missing from live after the non-single-formula and multipack cleanup.
SELECT count(*) AS upserted_rows
FROM public.upsert_catalog_product_feed((SELECT (
      CASE
        WHEN md5(payload_text) = 'c5956b4f75b8e8f53edd2c119cb7335f' THEN payload_text
        ELSE (1 / (CASE WHEN payload_text IS NULL THEN 0 ELSE 0 END))::TEXT
      END
    )::jsonb
    FROM (SELECT convert_from(decode('', 'base64'), 'UTF8') AS payload_text) AS payload_guard));
